        print_hex(out, 64);
        printf("\n");
    }
    /* Length 16, seek 16 on abc */
    {
        blake3_hasher h;
        blake3_hasher_init(&h);
        blake3_hasher_update(&h, "abc", 3);
        uint8_t out[16];
        blake3_hasher_finalize_seek(&h, 16, out, 16);
