static const char *g_progname = "b3sum";

static void print_usage_default(FILE *f) {
    fputs("Usage: executable [OPTIONS] [FILE]...\n", f);
}

static void print_more_info(FILE *f) {
    fputs("\nFor more information, try '--help'.\n", f);
