typedef struct {
    int keyed;
    int has_derive_key;
    const char *derive_key_ctx;
    int has_length;
    uint64_t length;
    int has_seek;
    uint64_t seek;
    int has_num_threads;
    uint64_t num_threads;
    int no_mmap;
    int no_names;
    int raw;
    int tag;
    int check;
